import json
flags = {}
with open('kai/ledger/log.jsonl') as f:
    for l in f:
        try:
            e = json.loads(l.strip())
            if e.get('action') == 'FLAG':
                flags[e['task_id']] = {'severity': e.get('severity','?'), 'note': e.get('note','')[:80]}
            if e.get('action') in ('CLOSE','VERIFY') and e.get('task_id','') in flags:
                del flags[e['task_id']]
        except: pass
for k,v in sorted(flags.items()):
    print(f'{k} [{v[\"severity\"]}] {v[\"note\"]}')
print(f'\nTotal unresolved: {len(flags)}')
"
